import re

def slugify(s: str) -> str:
    """Convert string to lowercase-hyphen slug."""
    s = s.lower()
    s = re.sub(r'[^a-z0-9]+', '-', s)
    s = s.strip('-')
    return s

def truncate_middle(s: str, n: int) -> str:
    """Truncate string to n chars, keeping ends with '…' in middle if len > n."""
    if len(s) <= n:
        return s
    remaining = n - 1
    start_len = remaining // 2
    end_len = remaining - start_len
    return s[:start_len] + '…' + s[-end_len:]

def word_count(s: str) -> int:
    """Count words in string."""
    return len(s.split())


if __name__ == '__main__':
    print(slugify('Hello World!'))
    print(slugify('foo---bar baz'))
    print(truncate_middle('hello world', 5))
    print(truncate_middle('hello', 10))
    print(word_count('one two three'))
    print(word_count(''))
