import unittest
from solution import slugify, truncate_middle, word_count


class TestSlugify(unittest.TestCase):
    def test_basic(self):
        self.assertEqual(slugify('Hello World!'), 'hello-world')

    def test_multiple_dashes(self):
        self.assertEqual(slugify('foo---bar baz'), 'foo-bar-baz')

    def test_empty_string(self):
        self.assertEqual(slugify(''), '')

    def test_only_special_chars(self):
        self.assertEqual(slugify('!!!###'), '')

    def test_mixed_case_and_numbers(self):
        self.assertEqual(slugify('Test123ABC'), 'test123abc')


class TestTruncateMiddle(unittest.TestCase):
    def test_basic(self):
        self.assertEqual(truncate_middle('hello world', 5), 'he…ld')

    def test_no_truncation_needed(self):
        self.assertEqual(truncate_middle('hello', 10), 'hello')

    def test_exact_length(self):
        self.assertEqual(truncate_middle('hello', 5), 'hello')

    def test_very_short_target(self):
        self.assertEqual(truncate_middle('hello world', 3), 'h…d')

    def test_empty_string(self):
        self.assertEqual(truncate_middle('', 5), '')


class TestWordCount(unittest.TestCase):
    def test_basic(self):
        self.assertEqual(word_count('one two three'), 3)

    def test_empty_string(self):
        self.assertEqual(word_count(''), 0)

    def test_single_word(self):
        self.assertEqual(word_count('hello'), 1)

    def test_multiple_spaces(self):
        self.assertEqual(word_count('one  two   three'), 3)


if __name__ == '__main__':
    unittest.main()
